156	impl ReadNumState {
157	    fn new(first_byte: i32) -> Self {
158	        ReadNumState {
159	            current: first_byte,
160	            count: 0,
161	            buf: [0u8; L_MAX_LEN_NUM + 1],
162	        }
163	    }
