//! `LuaUserData` — Lua's heap-allocated userdata. Carries a typed byte
//! buffer plus optional user values (a Vec of TValues).

use std::cell::RefCell;

use crate::gc::GcRef;
use crate::value::{LuaTable, LuaValue};

#[derive(Debug)]
pub struct LuaUserData {
    pub data: Box<[u8]>,
    pub uv: Vec<LuaValue>,
