/// TODO(port): std::process::Child — popen not yet implemented.
fn io_pclose(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: return luaL_execresult(L, l_pclose(L, p->f));
    let p = get_lstream(state)?;
