    // C: volatile lua_CFunction cf = p->closef; p->closef = NULL; return (*cf)(L);
    let p = get_lstream(state)?;
    let cf = p.close_fn.take().ok_or_else(|| {
        LuaError::runtime(format_args!("attempt to close an already-closed file"))
    })?;

